package com.recettealarm.app;import android.app.*;import android.media.*;import android.os.*;import android.view.*;import android.widget.*;
public class AlarmActivity extends Activity{MediaPlayer mp;Vibrator vib;public void onCreate(Bundle b){super.onCreate(b);getWindow().addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON|WindowManager.LayoutParams.FLAG_SHOW_WHEN_LOCKED|WindowManager.LayoutParams.FLAG_TURN_SCREEN_ON);LinearLayout r=UI.root(this);r.addView(UI.tv(this,"⏰ TEMPS ÉCOULÉ !",34,1));r.addView(UI.tv(this,getIntent().getStringExtra("note"),24,1));Button stop=UI.btn(this,"ARRÊTER");Button plus=UI.btn(this,"+5 MIN");Button ok=UI.btn(this,"J'ai vérifié le plat");r.addView(stop);r.addView(plus);r.addView(ok);startNoise();stop.setOnClickListener(v->finish());ok.setOnClickListener(v->finish());plus.setOnClickListener(v->{AlarmReceiver.schedule(this,5*60_000,"Rappel +5 minutes : vérifie le plat","Rappel cuisson");finish();});}
 void startNoise(){try{mp=MediaPlayer.create(this,android.provider.Settings.System.DEFAULT_ALARM_ALERT_URI);mp.setLooping(true);mp.start();}catch(Exception e){}vib=(Vibrator)getSystemService(VIBRATOR_SERVICE);if(Build.VERSION.SDK_INT>=26)vib.vibrate(VibrationEffect.createWaveform(new long[]{0,800,400,800},0));else vib.vibrate(new long[]{0,800,400,800},0);}public void onDestroy(){super.onDestroy();if(mp!=null){mp.stop();mp.release();}if(vib!=null)vib.cancel();}}
